// Heap 메모리 관리자

export interface HeapValue {
  val: number;
  refCount?: number;
}

export class HeapManager {
  private heap: Map<number, HeapValue>;
  private nextPtr: number = 0;

  constructor() {
    this.heap = new Map();
  }

  /**
   * Heap에 Value를 할당하고 Ptr 반환
   */
  allocate(value: HeapValue): number {
    const ptr = this.nextPtr++;
    this.heap.set(ptr, { val: value.val, refCount: 1 });
    return ptr;
  }

  /**
   * Ptr로 Value 조회
   */
  get(ptr: number): HeapValue | undefined {
    return this.heap.get(ptr);
  }

  /**
   * RefCount 증가 (참조 추가)
   */
  incrementRef(ptr: number): void {
    const value = this.heap.get(ptr);
    if (value) {
      value.refCount = (value.refCount || 1) + 1;
    }
  }

  /**
   * RefCount 감소 (참조 제거)
   */
  decrementRef(ptr: number): void {
    const value = this.heap.get(ptr);
    if (value && value.refCount) {
      value.refCount--;
      if (value.refCount === 0) {
        this.heap.delete(ptr);
      }
    }
  }

  /**
   * RefCount 조회
   */
  getRefCount(ptr: number): number {
    const value = this.heap.get(ptr);
    return value?.refCount || 0;
  }

  /**
   * Heap 상태 출력
   */
  dump(): void {
    console.log('=== Heap State ===');
    this.heap.forEach((value, ptr) => {
      console.log(`  [${ptr}] val: ${value.val}, refCount: ${value.refCount}`);
    });
  }
}

